#include <stdio.h>
#include <string.h>

int count_vk(const char *s, int len) {
    int count = 0;
    for (int i = 0; i < len - 1; i++) {
        if (s[i] == 'V' && s[i+1] == 'K') {
            count++;
        }
    }
    return count;
}

int main() {
    char s[101];
    scanf("%s", s);
    int len = strlen(s);

    if (len == 1 && s[0] == 'V') {
        printf("0\n");
        return 0;
    }
    if ((len == 2 && strcmp(s, "VK") == 0) || 
        (len == 2 && strcmp(s, "VV") == 0) || 
        (len == 2 && strcmp(s, "KK") == 0)) {
        printf("1\n");
        return 0;
    }

    int max = count_vk(s, len);

    for (int i = 0; i < len; i++) {
        char original = s[i];
        s[i] = 'V';
        int current = count_vk(s, len);
        if (current > max) {
            max = current;
        }
        s[i] = 'K';
        current = count_vk(s, len);
        if (current > max) {
            max = current;
        }
        s[i] = original;
    }

    printf("%d\n", max);
    return 0;
}
